import { d3_values } from '../../../utils/zcutils';
import { getRange } from '../../../legend/colorband/colorband-brush-helpers';

export function LegendBrushDataFinder(instanceMap, type, selection, forced) {
    let { brushOptions } = instanceMap.instance.options.component,
        { reversed } = brushOptions,
        data = getRange(brushOptions, selection);

    return reversed ? d3_values(data).reverse() : data;
}
